const allItems = $input.all();

function extractHits(responseJson) {
  if (responseJson && responseJson.data) {
    if (Array.isArray(responseJson.data.hits)) return responseJson.data.hits;
    if (Array.isArray(responseJson.data.opportunities)) return responseJson.data.opportunities;
    if (Array.isArray(responseJson.data.oppHits)) return responseJson.data.oppHits;
    if (Array.isArray(responseJson.data)) return responseJson.data;
  }
  if (Array.isArray(responseJson.oppHits)) return responseJson.oppHits;
  if (Array.isArray(responseJson.opportunities)) return responseJson.opportunities;
  if (Array.isArray(responseJson.searchResult)) return responseJson.searchResult;
  if (Array.isArray(responseJson.hits)) return responseJson.hits;
  return null;
}

const seen = new Set();
const mergedHits = [];
let totalRawCount = 0;
let envelopeUnrecognizedCount = 0;
let allQueriesZeroHits = true;

for (const item of allItems) {
  const rj = item.json;
  const hits = extractHits(rj);
  if (hits === null) {
    envelopeUnrecognizedCount++;
    continue;
  }
  if (hits.length > 0) allQueriesZeroHits = false;
  totalRawCount += hits.length;
  for (const grant of hits) {
    const key = grant.oppNumber || grant.id || JSON.stringify(grant).substring(0, 60);
    if (!seen.has(key)) {
      seen.add(key);
      mergedHits.push(grant);
    }
  }
}

if (envelopeUnrecognizedCount === allItems.length) {
  throw new Error(`Grants.gov API response envelope unrecognized across all ${allItems.length} fetch calls. Raw response keys: ${Object.keys(allItems[0]?.json || {}).join(', ')}. Investigate API schema change.`);
}

if (allQueriesZeroHits && allItems.length > 0 && envelopeUnrecognizedCount < allItems.length) {
  throw new Error(`All ${allItems.length} Grants.gov queries returned 0 hits. Possible query parameter mismatch (e.g. oppStatuses format) or API filter issue. Investigate request body schema.`);
}

const firstGrantKeys = mergedHits.length > 0 ? Object.keys(mergedHits[0]).join(', ') : 'no grants';

return [{
  json: {
    hits: mergedHits,
    totalRawCount,
    deduplicatedCount: mergedHits.length,
    envelopeUnrecognizedCount,
    firstGrantKeys
  }
}];

const today = new Date();
today.setHours(0,0,0,0);

const FOCUS_CATEGORIES = {
  'workforce development': ['workforce development', 'workforce', 'job training', 'employment'],
  'rural broadband': ['rural broadband', 'broadband', 'rural connectivity', 'internet access'],
  'veteran services': ['veteran', 'veterans services', 'military'],
  'early childhood education': ['early childhood', 'early childhood education', 'preschool', 'head start', 'child care']
};

function matchesFocusArea(grant) {
  const searchText = [
    (grant.oppTitle || grant.title || ''),
    (grant.synopsis || grant.description || ''),
    (grant.agencyName || grant.agency || ''),
    (grant.CFDANumbers || ''),
    (grant.oppNumber || grant.id || '')
  ].join(' ').toLowerCase();
  const matched = [];
  for (const [category, keywords] of Object.entries(FOCUS_CATEGORIES)) {
    if (keywords.some(kw => searchText.includes(kw))) {
      matched.push(category);
    }
  }
  return matched;
}

function getFundingCeiling(grant) {
  const raw = grant.awardCeiling
    || grant.award_ceiling
    || grant.estimatedTotalProgramFunding
    || grant.estimated_total_program_funding
    || grant.totalFunding
    || grant.total_funding
    || 0;
  return typeof raw === 'string' ? parseFloat(raw.replace(/[^0-9.]/g, '')) || 0 : Number(raw) || 0;
}

function getDaysUntilDeadline(grant) {
  const raw = grant.closeDate
    || grant.close_date
    || grant.closingDate
    || grant.archiveDate
    || grant.archive_date
    || '';
  if (!raw) return -1;
  const deadline = new Date(raw);
  if (isNaN(deadline.getTime())) return -1;
  const diffMs = deadline.getTime() - today.getTime();
  return Math.floor(diffMs / (1000 * 60 * 60 * 24));
}

function getGrantTitle(grant) {
  return grant.oppTitle || grant.title || grant.opportunity_title || 'Untitled';
}

function getAgency(grant) {
  return grant.agencyName || grant.agency_name || grant.agencyCode || grant.agency || 'Unknown Agency';
}

function getDeadlineRaw(grant) {
  return grant.closeDate || grant.close_date || grant.closingDate || grant.archiveDate || grant.archive_date || 'Unknown';
}

function getGrantId(grant) {
  return grant.oppNumber || grant.opp_number || grant.id || grant.opportunity_id || '';
}

function getSynopsis(grant) {
  return (grant.synopsis || grant.description || grant.summary || '').substring(0, 500);
}

const rawData = $input.first().json;
const hits = rawData.hits || [];

let deadlineSchemaWarning = null;

if (hits.length > 0) {
  const allZeroCeiling = hits.every(g => getFundingCeiling(g) === 0);
  const allInvalidDeadline = hits.every(g => getDaysUntilDeadline(g) === -1);

  if (allZeroCeiling && allInvalidDeadline) {
    throw new Error(`Schema parse failure: All ${hits.length} grants returned ceiling=0 and daysLeft=-1. Likely API field name change. First grant keys: ${rawData.firstGrantKeys}. Investigate Grants.gov v2 field mapping.`);
  }

  if (allInvalidDeadline && !allZeroCeiling) {
    deadlineSchemaWarning = `SCHEMA DRIFT WARNING: All ${hits.length} grants have unreadable deadline fields (daysLeft=-1) but funding ceilings are readable. Deadline field name may have changed. All grants will fail the deadline filter, producing an empty digest. Investigate Grants.gov v2 deadline field mapping. First grant keys: ${rawData.firstGrantKeys}`;
  }
}

const qualifying = [];
const borderline = [];
const skipped = [];

for (const grant of hits) {
  const matchedAreas = matchesFocusArea(grant);
  const ceiling = getFundingCeiling(grant);
  const daysLeft = getDaysUntilDeadline(grant);
  const grantId = getGrantId(grant);

  const focusPass = matchedAreas.length > 0;
  const ceilingPass = ceiling >= 250000;
  const deadlinePass = daysLeft >= 21;

  const passCount = [focusPass, ceilingPass, deadlinePass].filter(Boolean).length;

  let grantsGovLink;
  if (grantId) {
    grantsGovLink = `https://www.grants.gov/search-results-detail/${grantId}`;
  } else {
    grantsGovLink = 'https://www.grants.gov/search-results';
  }

  const enriched = {
    oppNumber: grantId,
    title: getGrantTitle(grant),
    agency: getAgency(grant),
    fundingCeiling: ceiling,
    deadlineDate: getDeadlineRaw(grant),
    daysUntilDeadline: daysLeft,
    matchedFocusAreas: matchedAreas,
    grantsGovLink,
    synopsis: getSynopsis(grant),
    focusPass,
    ceilingPass,
    deadlinePass
  };

  if (passCount === 3) {
    qualifying.push(enriched);
  } else if (passCount === 2) {
    borderline.push(enriched);
  } else {
    skipped.push(enriched.oppNumber);
  }
}

return [{
  json: {
    qualifying,
    borderline,
    skippedCount: skipped.length,
    totalEvaluated: hits.length,
    hasQualifying: qualifying.length > 0,
    runDate: today.toISOString().split('T')[0],
    parseFailure: false,
    deadlineSchemaWarning
  }
}];

const data = $input.first().json;
const allQualifying = data.qualifying || [];
// Cap at 10 grants to avoid timeout
const qualifying = allQualifying.slice(0, 10);

const OPENAI_API_KEY = $env.OPENAI_API_KEY;

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function callOpenAIWithRetry(prompt, retryOn429 = true) {
  const requestOptions = {
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${OPENAI_API_KEY}`
    },
    body: {
      model: 'gpt-4o-mini',
      messages: [{ role: 'user', content: prompt }],
      max_tokens: 150,
      temperature: 0.7
    },
    json: true
  };

  let response;
  try {
    response = await $http.request(requestOptions);
  } catch (err) {
    // Check if it was a 429 and retry once after 2s
    if (retryOn429 && err.message && err.message.includes('429')) {
      await sleep(2000);
      return callOpenAIWithRetry(prompt, false);
    }
    throw err;
  }
  return response;
}

async function generateBlurb(grant) {
  const focusAreaList = grant.matchedFocusAreas.join(', ');
  const ceilingFormatted = new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(grant.fundingCeiling);

  const prompt = `You are a grants writer for a nonprofit focused on workforce development, rural broadband, veteran services, and early childhood education. Write a compelling 2-3 sentence blurb explaining why this federal grant is a strong fit for our organization. Be specific about the focus area alignment, NOT generic. Do not start with "This grant".

Grant Title: ${grant.title}
Agency: ${grant.agency}
Funding Ceiling: ${ceilingFormatted}
Deadline: ${grant.deadlineDate} (${grant.daysUntilDeadline} days away)
Matched Focus Areas: ${focusAreaList}
Synopsis excerpt: ${grant.synopsis}

Write the 2-3 sentence blurb:`;

  const result = await callOpenAIWithRetry(prompt);
  return result.choices?.[0]?.message?.content?.trim() || null;
}

const enrichedGrants = [];
let openaiSuccessCount = 0;
let fallbackCount = 0;

for (let i = 0; i < qualifying.length; i++) {
  const grant = qualifying[i];
  // 200ms delay between calls (skip before first call)
  if (i > 0) {
    await sleep(200);
  }

  let blurb;
  let blurbSource;
  try {
    const generated = await generateBlurb(grant);
    if (generated && generated.length >= 50) {
      blurb = generated;
      blurbSource = 'openai';
      openaiSuccessCount++;
    } else {
      throw new Error('Generated blurb too short or null');
    }
  } catch (e) {
    blurb = `Strong alignment with ${grant.matchedFocusAreas.join(' and ')} focus areas. Funding ceiling of $${grant.fundingCeiling.toLocaleString()} meets program threshold. Deadline in ${grant.daysUntilDeadline} days.`;
    blurbSource = 'fallback';
    fallbackCount++;
  }
  enrichedGrants.push({ ...grant, blurb, blurbSource });
}

const allBlurbsFailed = qualifying.length > 0 && fallbackCount === qualifying.length;

return [{
  json: {
    qualifying: enrichedGrants,
    borderline: data.borderline,
    skippedCount: data.skippedCount,
    totalEvaluated: data.totalEvaluated,
    runDate: data.runDate,
    deadlineSchemaWarning: data.deadlineSchemaWarning || null,
    blurbsGenerated: true,
    openaiSuccessCount,
    fallbackCount,
    allBlurbsFailed
  }
}];

const data = $input.first().json;
const qualifying = data.qualifying || [];

let blurbsValid = true;
let blurbsValidReason = 'All blurbs meet length threshold';
let blurbAlertLevel = null;
let useBlurbFallbackPath = false;

if (data.allBlurbsFailed === true) {
  // OpenAI is completely down - soft WARNING path: post digest with fallback blurbs + warning
  // Do NOT treat as hard ERROR (reserve ERROR for data pipeline failures)
  blurbsValid = true; // allow digest to proceed with fallback blurbs
  blurbAlertLevel = 'WARNING';
  blurbsValidReason = 'All blurbs used fallback template - OpenAI API may be down. Digest posted with template blurbs.';
  useBlurbFallbackPath = true;
} else {
  let invalidCount = 0;
  for (const grant of qualifying) {
    if (!grant.blurb || grant.blurb.length < 50) {
      blurbsValid = false;
      invalidCount++;
    }
  }
  if (!blurbsValid) {
    blurbsValidReason = `${invalidCount} blurb(s) below 50-char threshold`;
  }
}

return [{
  json: {
    ...data,
    blurbsValid,
    blurbsValidReason,
    blurbAlertLevel,
    useBlurbFallbackPath
  }
}];

const data = $input.first().json;
const qualifying = data.qualifying || [];
const borderline = data.borderline || [];
const runDate = data.runDate || new Date().toISOString().split('T')[0];

const formatCurrency = (n) => new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(n);

const items = qualifying.map(g => ({
  title: g.title,
  agency: g.agency,
  fundingCeiling: formatCurrency(g.fundingCeiling),
  fundingCeilingRaw: g.fundingCeiling,
  deadline: g.deadlineDate,
  daysUntilDeadline: g.daysUntilDeadline,
  focusAreas: g.matchedFocusAreas,
  grantsGovLink: g.grantsGovLink,
  blurb: g.blurb,
  blurbSource: g.blurbSource
}));

const borderlineItems = borderline.map(g => ({
  title: g.title,
  agency: g.agency,
  fundingCeiling: formatCurrency(g.fundingCeiling),
  deadline: g.deadlineDate,
  daysUntilDeadline: g.daysUntilDeadline,
  focusAreas: g.matchedFocusAreas,
  grantsGovLink: g.grantsGovLink,
  missedCriteria: [
    !g.focusPass ? 'focus area mismatch' : null,
    !g.ceilingPass ? `funding ceiling below $250k (${formatCurrency(g.fundingCeiling)})` : null,
    !g.deadlinePass ? `deadline within 21 days (${g.daysUntilDeadline} days)` : null
  ].filter(Boolean)
}));

const hasFallbackBlurbs = (data.fallbackCount || 0) > 0;
let blurbWarning = null;
if (data.useBlurbFallbackPath) {
  blurbWarning = `WARNING: All ${items.length} blurb(s) used fallback template - OpenAI API may be down. Review blurbs before sharing.`;
} else if (hasFallbackBlurbs) {
  blurbWarning = `Note: ${data.fallbackCount} of ${items.length} blurb(s) used fallback template (OpenAI partial failure).`;
}

const summary = `Grant Digest for ${runDate}: ${items.length} qualifying grant(s) found across ${data.totalEvaluated} evaluated. Focus areas: workforce development, rural broadband, veteran services, early childhood education. Funding threshold: $250k+. Deadline window: 21+ days out.`;

const alertLevel = data.blurbAlertLevel || null;

return [{
  json: {
    summary,
    items,
    borderline: borderlineItems,
    meta: {
      runDate,
      totalEvaluated: data.totalEvaluated,
      qualifyingCount: items.length,
      borderlineCount: borderlineItems.length,
      skippedCount: data.skippedCount,
      openaiSuccessCount: data.openaiSuccessCount,
      fallbackCount: data.fallbackCount
    },
    blurbWarning,
    alertLevel,
    deadlineSchemaWarning: data.deadlineSchemaWarning || null,
    isEmpty: false
  }
}];

const data = $input.first().json;
const runDate = data.runDate || new Date().toISOString().split('T')[0];

let staticData = $getWorkflowStaticData('global');
if (!staticData.consecutiveEmptyDays) staticData.consecutiveEmptyDays = 0;
staticData.consecutiveEmptyDays = (staticData.consecutiveEmptyDays || 0) + 1;
const consecutiveEmptyDays = staticData.consecutiveEmptyDays;

const borderlineItems = (data.borderline || []).map(g => ({
  title: g.title,
  agency: g.agency,
  fundingCeiling: g.fundingCeiling,
  deadline: g.deadlineDate,
  daysUntilDeadline: g.daysUntilDeadline,
  focusAreas: g.matchedFocusAreas,
  grantsGovLink: g.grantsGovLink,
  missedCriteria: [
    !g.focusPass ? 'focus area mismatch' : null,
    !g.ceilingPass ? 'funding ceiling below $250k' : null,
    !g.deadlinePass ? `deadline within 21 days (${g.daysUntilDeadline} days)` : null
  ].filter(Boolean)
}));

const summary = `Grant Digest for ${runDate}: No grants meeting all criteria today (${data.totalEvaluated} evaluated). Focus areas: workforce development, rural broadband, veteran services, early childhood education.`;

let alertLevel = null;
let consecutiveWarning = null;
if (consecutiveEmptyDays >= 3) {
  alertLevel = 'WARNING';
  consecutiveWarning = `Grant digest has returned zero qualifying results for ${consecutiveEmptyDays} consecutive business days — verify API connectivity and query parameters.`;
}

return [{
  json: {
    summary,
    items: [],
    borderline: borderlineItems,
    isEmpty: true,
    consecutiveEmptyDays,
    alertLevel,
    consecutiveWarning,
    deadlineSchemaWarning: data.deadlineSchemaWarning || null,
    meta: {
      runDate,
      totalEvaluated: data.totalEvaluated,
      qualifyingCount: 0,
      borderlineCount: borderlineItems.length,
      skippedCount: data.skippedCount
    }
  }
}];

const inputData = $input.first().json;
// In n8n error paths, the error message may appear in different fields depending on node type
const errorMessage = inputData.error
  || inputData.message
  || inputData.errorMessage
  || 'Unknown error during grant digest workflow - check n8n execution log for details';

return [{
  json: {
    summary: 'WORKFLOW FAILURE: Grants.gov daily digest failed to complete. Manual investigation required.',
    items: [],
    error: errorMessage,
    alertLevel: 'ERROR',
    runDate: new Date().toISOString().split('T')[0]
  }
}];
